# break — выход из цикла
for i in range(10):
    if i == 5:
        break
    print(i)        # 0 1 2 3 4

print('---')

# continue — пропуск итерации
for i in range(10):
    if i % 2 == 0:
        continue    # пропускаем чётные
    print(i)        # 1 3 5 7 9

print('---')

# else у цикла — выполняется если цикл НЕ прерван break
for n in range(2, 10):
    for d in range(2, n):
        if n % d == 0:
            break
    else:
        # d перебрали все значения без break → n простое
        print(f'{n} — простое')
